(73, 90, 'عاطفه عاطفی', NULL, '09024155308', '11', 'خراسان رضوی', '153', 'مشهد', 'هفت تیر', NULL, 'متاهل', '1362', NULL, 'با سلام \nبنده ۳۸ سال سن دارم  لیسانس حسابداری مالی دارم متاهل و دارای یک دختر ۱۵ ساله هستم سابقه کار حسابداری حرفه ای ندارم مدت ۲ ماه در کارخانه رب خرم قسمت حسابداری کار کردم که مربوط به ۱۰سال پیش هست و بعد به مدت ۱۰ سال به عنوان معاون در مهد کودک  مشغول شدم که مهد به علت کرونا بسته شد  و طی این ده سال دو کتاب هم نوشتم که چاپ شد وبه عنوان نویسنده بیمه تامین اجتماعی شدم وبه مدت تقریبا ۱۰سال سابقه بیمه دارم', 0, NULL, 'کمک حسابدار', 'قانون کار', NULL, 0, 'بدون سابقه کار', '2021-10-31 10:51:20', '2021-10-31 10:52:41'),
