(368, 453, 'فرشته اسدالهی مقدم', NULL, '09389539699', '11', 'خراسان رضوی', '153', 'مشهد', 'سرافرازان', NULL, 'مجرد', '1371', NULL, 'از بهمن ماه سال ۹۴ تا اواسط مهر ماه ۹۶ در فروشگاه زنجیره ای روناز مشغول به کار حسابداری مالی و فروش و خزانه فعالیت میکردم،و فروشگاه تعطیل شدبه صلاحدید مدیر فروشگاه؛ آبان‌۹۶ تا ۳۱‌مرداد ۹۹ در شرکت گروه خودرویی کاظمی پارس حسابداری بخش مالی فروش و خزانه و آماده کردن گزارشات فصلی رو انجام می‌دادم و بابت اینکه شرکت به درخواست مدیر عامل به حالت تعلیق اعلام شد و بلافاصله  از شهریور ماه ۹۹  پیرو اینکه بلافاصله مجدد مشغول به کار شدم بازم به ذکر است که چون حسابداری مجموعه بودم و در جریان تصمیم مدیر عامل شرکت بودم به در خواست مدیر عامل حین انجام فعالیت دنبال کار بودم و تا هم اکنون درهلدینگ قسمت حسابداری مالی و تهیه گزارشات فصلی مشغول به کار‌ می‌باشم؛و به جهت جو متشنج و پر‌از حاشیه تصمیم به جابه جایی محل کار و موقعیت با پیشرفت روز افزون رو دارم.سابقه کارهای مالیاتی را شامل می شود', 0, NULL, 'حسابدار', 'توافقی', NULL, 1, '7 سال', '2021-12-03 17:30:49', '2022-07-28 18:55:25'),
(369, 454, 'مونا مسلمی', 'moslemi.66.44@gmail.com', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'توانایی در مدیریت تیم مالی هر مجموعه و پیاده سازی صفر تا صد امور مالی از سند روزنامه تا بستن حسابها.....شرکت در هیاتهای مالیاتی و دفاعیات لازم... \nتنظیم و ارسال اظهارنامه های مالیاتی و صورت معاملات فصلی و.... \nگزارشدهی مدیریتی و اتخاذ تصمیمات مدیریتی و مالی', NULL, NULL, 'مدیر مالی', '15 تا 20 میلیون تومان', NULL, 1, '10 سال', '2021-12-03 19:44:22', '2021-12-03 19:50:55'),
