(901, 1046, 'ناهید نیکبخت', 'Nani.nik90@yahoo.com', '09352699174', '8', 'تهران', '117', 'تهران', 'تهرانپارس شرقی - منطقه 4', NULL, 'مجرد', '1361', NULL, 'بسیار علاقه مند هستم در کار مرتبط با رشته تحصیلی پیشرفت کنم . و کسب مهارت در شرکت شما و حرفه ای شدن در کار و ارتقاء شغلی یکی علایق بنده محسوب میشود. یادگیری وکار با هرگونه نرم افزاری جزء علایق بنده هستش. در مورد حقوق درخواستی با توجه ب استعداد و مهارتها و تحصیلاتی که دارم احساس میکنم با این شرایط حقوقم تا ۱۰ میلیون باشه کفایت میکنه', 0, NULL, 'حسابدار', '9 تا 12 میلیون تومان', NULL, 0, '2 سال', '2022-01-15 09:45:41', '2022-01-15 10:52:44'),
