(1049, 1197, 'سعیده کیان', 'saeedehkian68@yahoo.com', '09372467712', '8', 'تهران', '117', 'تهران', 'اتوبان تهران کرج - منطقه 21', NULL, 'مجرد', '1368', NULL, 'ثبت و تنظیم کلیه اسناد حسابداری\nتسلط کامل به امور خزانه\nتسلط کامل به امور انبار\nمسلط به تهیه و تنظیم لیست حقوق و دستمزد\nارسال لیست بیمه ومالیات حقوق\nتهیه و ارسال گزارش ارزش افزوده و لیست معاملات فصلی\nمسلط به ثبت دفاترتجاری و قانونی\nآشنایی با بستن حسابها و همکاری در تنظیم و ارسال اظهارنامهمالیات بر عملکرد\nمسلط به امور اداری و استخدامی پرسنل\nدارای روحیه کار تیمی ومسئولیت پذیری کاری\nآشنایی با قوانین ومقررات مالیاتی و قانون کار و تامین اجتماعی', 0, NULL, 'حسابدار', '9 تا 12 میلیون تومان', NULL, 1, '7 سال', '2022-01-25 08:05:39', '2022-01-25 08:19:05'),
