(1051, 1199, 'عبداله رجبی', 'rajabi.ab@gmail.com', '09128358785', '8', 'تهران', '117', 'تهران', 'مجیدیه و شمس آباد - منطقه 4', NULL, 'متاهل', '1363', 'معافیت دائم', 'دارای مدارک دانشگاهی رشته حسابداری (کارشناسی، ارشد، دکتری) و بیش از 16 سال سابقه مرتبط از حسابدار تا مدیر و مشاور مالی. مدرس اکسل. نویسنده و طراح برنامه های کاربردی مختلف در زمینه های مالی، بهای تمام شده، حقوق و اداری و...', 1, NULL, 'مشاور مالی', '9 تا 12 میلیون تومان', NULL, 1, '17 سال', '2022-01-25 08:50:34', '2022-01-25 09:20:29'),
(1052, 1200, 'محمودرضا خزایی', 'khazaeimailbox@yahoo.com', '09226567450', '8', 'تهران', '117', 'تهران', 'نیروی هوایی - منطقه 13', NULL, 'مجرد', '1353', 'پایان خدمت', 'اینجانب محمودرضا خزایی از سال 72 در دانشگاه آزاد پذیرفته و از آن زمان تا کنون، از پایینترین تا بالاترین سطح امور مالی و در کلیه صنایع (تولیدی،بازرگانی، درمانی،....) شاغل و مدارج ترقی را تا کنون طی کرده ام. در کل حدود 28 سال فعالیت حرفه ای بنده فقط در 4 شرکت مطرح ایران بطورفعال بوده و در 18 سال سال اخیر بعنوان مدیر فعال بوده ام همچنین شایان ذکر است که در این سالها در بیش از یکصدپروژه بصورت نیمه وقت بعنوان مشاور،مدیر و مدرس، استقرار سیستم،فعال بوده ام.\nتجربه تخصصی در  شرکت های تولیدی و انواع محاسبه بهای تمام شده.\nاستقرار سیستم های مالی در  مراکز درمانی، پارالل با سیستم(  اچ آی اس) در راستای گزارشات مالی و نیاز مراجع دولتی (دارایی،بیمه)\nتسلط به زبان انگلیسی', 1, NULL, 'مدیر مالی', '20 تا 25 میلیون تومان', NULL, 0, '27 سال', '2022-01-25 09:13:24', '2023-03-08 18:00:39'),
