(2985, 3638, 'مولود معتمدی', NULL, '09393069833', '17', 'فارس', '232', 'شیراز', '', NULL, 'متاهل', '1365', NULL, '۵ سال سابقه کاری با بیمه،مهارت های هفت گانه کامپیوتر رو بلد هستم. زبان انگلیسی رو در حد متوسط  رو به عالی بلدم . با نرم افزارهای مهر،سامان  ،نوین پرداز کار کردم . صبور هستم ،متعهد به کارم هستم و مسئولیت پذیرم', 0, NULL, 'حسابدار', '9 تا 12 میلیون تومان', NULL, 1, 'بیشتر از 5 سال', '2024-04-16 05:28:51', '2024-04-16 05:32:08'),
