(3436, 4208, 'علیرضا حلمی', 'alirezahelmibarati79@gmail.com', '09025463697', '11', 'خراسان رضوی', '153', 'مشهد', 'سرافرازان', NULL, 'مجرد', '1379', 'معافیت', 'کارشناسی ارشد حسابداری \nفردی دقیق و منظم با روحیه همکاری بالا ، انگیزه در یادگیری ، پشتکار در انجام فعالیت ، مدافع منافع مجموعه ، دارای ارتباطات اجتماعی همچنین در محیط کاری فردی فعال و با وجدان کاری بالا هستم\n هدف من در جستجوی شغل بهتر، ارتقاء حرفه‌ای در حوزه حسابداری و مالی است. من تجربه کاری مؤثر در این زمینه دارم و به دنبال فرصتی هستم که به من امکان دهد مهارت‌هایم را توسعه دهم و به یک موقعیت موثرتر دست یابم.', 1, NULL, 'حسابدار', 'توافقی', NULL, 0, 'بین 3 تا 4 سال', '2024-08-13 09:45:36', '2024-08-13 09:48:58'),
