(3636, 4462, 'امیرحسین مهمی', 'important20002@gmail.com', '09373440343', '8', 'تهران', '117', 'تهران', 'اندرزگو - منطقه 1', NULL, 'مجرد', '1371', 'معافیت', 'حسابدار ماهر و باتجربه در مدیریت مالی و حسابرسی\nدارای مهارت در تهیه، تنظیم، تجزیه و تحلیل صورت های مالی\nآشنا به نرم افزارهای حسابداری و مالی\nتوانا در حل مسائل و تصمیم گیری های مالی\nتسلط به حسابداری مدیریت\nیادگیری سریع کار با نرم افزارهای مالی و مهارت در استفاده از آن\nشرکت در دوره های مختلف و دارای گواهینامه از جمله تهیه و تنظیم صورتهای مالی، دوره حسابرسی عملیاتی و داخلی، مهارت های هفت گانه فناوری اطلاعات(ICDL)، تجزیه و تحلیل ریسک و ....', 1, NULL, 'حسابدار', '30 میلیون و بیشتر', NULL, 0, 'بین 8 تا 10 سال', '2025-03-26 11:09:30', '2025-03-26 12:35:58'),
