(3648, 4476, 'الهام علی ابادی', 'Sarsangi.elham@gmail.com', '09134545512', '31', 'یزد', '426', 'یزد', '', NULL, 'مجرد', '1368', NULL, 'مسلط به نرم افزار های مالی هلو کد ۳۳ و ۴۴ ، مجموعه افیس ( اکسل، ورد و... ) ، همکاران سیستم ، رایورز ، رافع ، سپیدار ، حسیب ، راهکاران ، تدارک ، نوسا\nمسلط بر ارزش افزوده ، سامانه مودیان، معاملات فصلی ، اظهارنامه عملکرد، ارسال لیست بیمه و مالیات حقوق، قوانین بیمه ، قرارداد پرسنل ، حسابداری بهای تمام شده ، حسابداری پیمانکاری ،صورت های مالی ،', 0, NULL, 'مدیر مالی', '25 تا 30 میلیون تومان', NULL, 0, 'بین 10 تا 15 سال', '2025-04-03 16:04:25', '2025-04-03 16:20:08'),
(3649, 4477, 'حمیده فخرحسینی', 'hamidefakhrhoseini@gmail.com', '09124780598', '5', 'البرز', '283', 'کرج', 'برغان', NULL, 'مجرد', '1365', NULL, 'آشنا به نرم افزار های مالی( سپیدار ، راهکاران،شایگان) و سامانه مودیان و سامانه جامع تجارت . توانایی کار در تیم و ارتباط موثر با مشتریان. متعهد به رعایت استانداردهای مالی و اخلاق حرفه ای، با دقت و مثبت اندیش با توانایی پیشرفت کار در محیط حجم کار بالا و به دنبال بهبود فرآیندهای مالی و افزایش کارایی سازمان', 0, NULL, 'حسابدار', '25 تا 30 میلیون تومان', NULL, 0, 'بین 10 تا 15 سال', '2025-04-04 14:33:19', '2025-04-04 23:14:51'),
(3650, 4478, 'ملیکا شبیه', 'melikashabih@gmail.com', '09919440307', '17', 'فارس', '232', 'شیراز', '', NULL, 'متاهل', '1380', NULL, 'انجام خدمات:\n\n✅تسلط به اکثر نرم افزار های حسابداری مثل (نیکان،شایگان،سپیدار،سورن،پرنس‌و...)\n\n✅طراحی داشبورد مدیریت و گزارش های مدیریتی با نرم افزار Excel , power BI\n\n✅ثبت اسناد حسابداری و تهیه گزارش‌های مالی\n\n✅کدگذاری نرم‌افزارهای حسابداری و انبارداری\n\n✅تهیه و تنظیم اظهارنامه مالیاتی و گزارش‌های فصلی\n\n✅مشاوره در بهینه‌سازی امور مالی کسب‌وکارها\n\nویژگی همکاری با من :\n\n✅دقت و سرعت بالا در انجام کارها\n\n✅امکان کار از راه دور و حضوری', 0, NULL, 'حسابدار', 'توافقی', NULL, 1, 'بیشتر از 5 سال', '2025-04-04 22:37:55', '2025-04-04 22:48:35'),
(3651, 4481, 'ولی اله کوکانی تفرشی', NULL, '09122415580', '14', 'زنجان', '206', 'زنجان', '', NULL, 'متاهل', '1339', 'اتمام سربازی', 'ضمن سلام و عرض ادب بنده بازنشسته با 35 سال سابقه کار در امور حسابداری در اداره و شرکت ها و اشنا به نرم افزلر های حسابداری ازجمله سپیدار و تدبیر و هلو و همچنین نرم افزار حقوق دستمزد و امور پرسنلی و افیس و میزان تحصیلات دیپلم و اکثرا مسولیت  حسابها با اینجانب بوده و ثبت سند و خزانه داری و بایگانی اسناد و ثبت کاردکس انبار نیز آشنایی دارم', 1, NULL, 'کمک حسابدار', '20 تا 25 میلیون تومان', NULL, 0, 'بیشتر از 20 سال', '2025-04-05 10:30:42', '2025-04-05 10:41:08'),
