(3810, 4673, 'افسانه لطفی', 'Lotfi673@yahoo.com', '09151634152', '11', 'خراسان رضوی', '153', 'مشهد', '', NULL, 'متاهل', '1363', NULL, 'مدیر و مشاور مالی با سابقه بیش از بیست سال در شرکت‌های تولیدی از جمله تولید آرد ، خوراک دام، فراورده های لبنی و… شرکت‌های شرکت‌های پخش و … با مدرک دکتری حسابداری', 0, NULL, 'مشاور مالی', 'بیش از 40 میلیون تومان', NULL, 1, 'بیشتر از 20 سال', '2025-06-16 17:13:56', '2025-06-16 18:15:30'),
(3811, 4674, 'زهرا جهانی متین', 'zahrajahanimatin@gmail.com', '09158109118', '11', 'خراسان رضوی', '153', 'مشهد', 'پردیس', NULL, 'متاهل', '1362', NULL, 'مدیر مالی با بیش از ۱۵ سال تجربه در صنایع تولیدی و پیمانکاری، متخصص در طراحی و پیاده‌سازی سیستم‌های مالی و حسابداری صنعتی. توانمند در تحلیل صورت‌های مالی، کنترل هزینه‌ها، بودجه‌بندی و مدیریت ریسک‌های مالی. سابقه موفق در هدایت تیم‌های مالی چند نفره، همکاری نزدیک با بانک‌ها و حسابرسان، و بهبود فرآیندهای مالیاتی و بیمه‌ای. مسلط به نرم‌افزارهای حسابداری و اکسل ، دارای روحیه حل مسئله و تصمیم‌گیری استراتژیک برای ارتقای عملکرد مالی سازمان.', 0, NULL, 'مدیر مالی', 'توافقی', NULL, 1, 'بین 15 تا 20 سال', '2025-06-16 17:51:55', '2025-09-21 10:09:53'),
(3812, 4675, 'مزینانی', 'Mazinanim76@gmail.com', '09120805429', '8', 'تهران', '117', 'تهران', '', NULL, 'مجرد', '1376', NULL, 'انجام امور مربوط به سامانه مودیان\nارزش افزوده\nبیمه مالیات حقوق دستمزد\nانبار\nفروش\nخزانه\nحسابداری مالی', 0, NULL, 'حسابدار', '15 تا 20 میلیون تومان', NULL, 0, 'بین 5 تا 7 سال', '2025-06-26 22:54:19', '2025-06-26 22:56:55'),
(3813, 4677, 'محسن فضل علی', 'mohsenfazlali12@gmail.com', '09927355707', '8', 'تهران', '135', 'رباط کریم', '', NULL, 'مجرد', '1381', 'معافیت', 'سلام وقتتون بخیر. اینجانب محسن فضل علی دانشجو ترم ۶ حسابداری دانشگاه آزاد اسلامی واحد شهریار هستم و دوره های کمک حسابدار و حسابداری تکمیلی و نرم سپیدار را گذرانده و مدرک فنی و حرفه ای آنها را دریافت کرده ام. یک دوره کارآموزی چهار ماهه به صورت پاره وقت در موسسه مالی و مالیاتی حسابگر در رباط کریم گذرانده ام. حال به دنبال یک شغل در یک شرکت معتبر هستم تا تجربه خود را افزایش دهم.', 1, NULL, 'کمک حسابدار', 'توافقی', NULL, 0, 'بدون سابقه کار', '2025-06-28 10:52:55', '2025-06-28 10:57:31'),
(3814, 4678, 'سعید موسوی', 'Smousavi2536@gmail.com', '09151105609', '11', 'خراسان رضوی', '153', 'مشهد', 'سرافرازان', NULL, 'متاهل', '1356', 'اتمام سربازی', 'مدیرومشاورمالی ومالیاتی و حسابدار ارشد', 1, NULL, 'سرپرست حسابداری', '30 تا 40 میلیون تومان', NULL, 0, 'بیشتر از 20 سال', '2025-06-30 11:52:58', '2025-07-01 21:44:27'),
(3815, 4679, 'مرضیه زحمتکش', NULL, '09014024872', '11', 'خراسان رضوی', '153', 'مشهد', 'رضا شهر', NULL, 'مجرد', '1374', NULL, NULL, 0, NULL, 'حسابدار', '20 تا 25 میلیون تومان', NULL, 0, 'کمتر از 5 سال', '2025-06-30 16:51:57', '2025-06-30 17:00:16'),
(3816, 4680, 'مائده پروانه', NULL, '09052606204', '11', 'خراسان رضوی', '153', 'مشهد', 'رضا شهر', NULL, 'مجرد', '1379', NULL, 'آشنایی به قوانین مالیاتی و بیمه و علاقه مند به یادگیری بیشتر.بی حاشیه هستم و فقط رویه کارم تمرکز دارم.توانایی درک و یادگیری بالا.آشنایی با ارزش افزوده و گزارشات فصلی و اظهارنامه عملکرد.رد کردن لیست بیمه و مالیات حقوق.محاسبه حقوق.آشنایی به سامانه مودیان.صورت مغایرت بانکی.آشنایی با سیستم crm (پیام گستر).ثبت اسناد حسابداری.تهیه گزارش سود و زیان.فرمول دهی بخش تولید سپیدار.ثبت تولید محصول در سپیدار.بستن انبار تولید سپیدار.آخرین حقوق دریافتی در سال ۱۴۰۴ ۲۸ت', 0, NULL, 'حسابدار', '25 تا 30 میلیون تومان', NULL, 1, 'بین 3 تا 4 سال', '2025-06-30 17:37:24', '2025-06-30 17:54:13'),
(3817, 4681, 'مهدی نژادحسین', 'mehdinezhadhosein32@gmail.com', '09221975730', '11', 'خراسان رضوی', '153', 'مشهد', 'بهمن', NULL, 'متاهل', '1358', 'اتمام سربازی', 'آقاهستم متاهل 46ساله ساکن شهرستان مشهد ابتدای جاده کلات باسابقه در بخش امور مالی و حسابداری با دو فرزند عضو رسمی  انجمن حسابداران جمهوری اسلامی ایران  با بیش از ده سال بیمه تامین اجتماعی', 1, NULL, 'حسابدار', '30 تا 40 میلیون تومان', NULL, 0, 'بین 15 تا 20 سال', '2025-07-01 00:49:47', '2025-08-02 23:50:02'),
(3818, 4682, 'اسماصغیر', NULL, '09015328577', '11', 'خراسان رضوی', '153', 'مشهد', 'قاسم اباد (شهرک غرب)', NULL, 'مجرد', '1383', NULL, 'با عرض ادب  با نرم افزار های هلو محک کاووش سپیدار کار کردم در یک شرکت حسابرسی مشغول به کار بودم به مدت چهار ماه در یک شرکت تجهیزات پزشکی حسابدار انبار بودم و یک شرکت پیمانکاری  کار میکردم', 0, NULL, 'کمک حسابدار', 'قانون کار', NULL, 0, 'کمتر از 1 سال', '2025-07-01 20:02:55', '2025-07-01 20:07:31'),
(3819, 4683, 'ملیکا شبانی', 'melika.shabani1400@gmail.com', '09388207418', '11', 'خراسان رضوی', '153', 'مشهد', 'عبدالمطلب', NULL, 'متاهل', '1381', NULL, 'ملیکا شبانی\nدانشجوی مقطع کارشناسی حسابداری \nدارای ۲ سال سابقه کار در زمینه کاری حسابداری می باشم\nدر یک مجموعه شامل دو شرکت\n✅️ روزنامه صبح امروز\n✅️ دهکده چاپ\nدر طول دوران کاری خود ، توانستم مهارت های زیادی کسب کنم \nمهارت های من شامل :\n✅️ تهیه صورت های مالی\n✅️ مدیریت حساب های پرداختنی /دریافتنی\n✅️ تهیه گزارشات مالی \n✅️ حقوق و دستمزد\n✅️ ثبت چک / فاکتور فروش و فاکتور خرید و...\n✅️ ورد و اکسل\n✅️ نرم افزار های : شایگان و محک\n✅️ مسلط به زبان انگلیسی', 0, NULL, 'حسابدار', 'قانون کار', NULL, 0, 'بین 1 تا 2 سال', '2025-07-01 20:03:11', '2025-07-03 03:29:02'),
