(3905, 4792, 'زهره زاهدی', 'Zohrezahedi222@gmail.com', '09171077974', '17', 'فارس', '257', 'سروستان', '', NULL, 'مجرد', '1361', NULL, 'من از ابتدای شروع فعالیت با شرکت پیمانکاری راه و ساختمان کار کردم.\nبا چند تا نرم افزار حسابداری کار کردم آفیس رو تجربی یاد گرفتم .\nمعمولا کارهای اداری و بانکی رو خودم انجام می‌دادم.\nبا سامانه های امور مالیاتی و تأمین اجتماعی کار کردم .', 0, NULL, 'سرپرست حسابداری', '30 تا 40 میلیون تومان', NULL, 0, 'بین 10 تا 15 سال', '2025-07-28 18:03:20', '2025-07-28 18:08:10'),
(3906, 4793, 'مهری طلاوری پور', NULL, '09350549997', '4', 'اصفهان', '78', 'شاهین شهر', '', NULL, 'متاهل', '1364', NULL, 'مسلط به اکسل،ورد\nمسلط به حسابداری برنامه پارسیان و ....\nانبارداری سیستمی و دفتری ،دفاتر روزنامه،دفاتر کل\nگزارشات مالی\n برنامه های حضور و غیاب \nمحاسبه حقوق و دستمزد پرسنل \nلیست بیمه\nخرید و فروش\nمطالبات', 0, NULL, 'حسابدار', 'توافقی', NULL, 0, 'کمتر از 5 سال', '2025-07-28 19:27:46', '2025-08-07 12:46:20'),
