(3908, 4796, 'مائده ملکی', NULL, '09196375114', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'یک سال و چهار ماه سابقه کار حسابداری \nمسلط به ورد و اکسل \nوصول مطالبات\nصورت مغایرت گیری بانکی \nثبت سند روزانه \nخرید و فروش', NULL, NULL, 'حسابدار', '20 تا 25 میلیون تومان', NULL, 0, 'بین 1 تا 2 سال', '2025-07-28 22:27:10', '2025-07-28 22:31:54'),
