(4140, 5078, 'الهه تقی نیا', 'elaheh.tn.2001@gmail.com', '09337154075', '11', 'خراسان رضوی', '153', 'مشهد', 'فرامرز عباسی', NULL, 'مجرد', '1380', NULL, 'کارفرمای محترم ، اینجانب  از مهر ماه ۱۴۰۱ تا مرداد ماه ۱۴۰۴ مشغول به فعالیتهای زیر بوده :\nکار با چهار نرم افزار حسابداری مختلف \nکار با نرم افزار واسط هشت \nکار با نرم افزار دیسک لیست \nکار با نرم‌افزار سالاری \nکار با اکسل و ورد \nکار با سامانه مودیان \n+ ارسال اظهارنامه مالیاتی ارزش افزوده \n+ ارسال صورت معاملات فصلی \n+ مغایرت گیری\n+ بایگانی اسناد\n+ثبت تنخواه \n+ ثبت دریافت و پرداخت \n+محاسبه حقوق دستمزد توسط اکسل', 0, NULL, 'حسابدار', 'قانون کار', NULL, 0, 'بین 1 تا 2 سال', '2025-08-19 12:04:02', '2025-08-19 12:23:03'),
(4141, 5079, 'minarahimi', 'rahimimina058@gmail.com', '09309297687', '11', 'خراسان رضوی', '153', 'مشهد', '17 شهریور', NULL, 'مجرد', '1385', NULL, 'دانشجو کارشناسی حسابداری\nسابقه چند ماه فعالیت در یک شرکت حسابداری خدماتی مالیاتی\nتسلط به انجام ثبت اسناد حسابداری ، فاکتورهای خرید و فروش ، تنخواه، مغایرت بانکی \nکار با نرم افزار رایسیس\nآشنایی با اکسل و سایر مجموعه آفیس\nآشنایی با سامانه مودیان\nآشنایی با نرم افزار محک', 0, NULL, 'کمک حسابدار', 'توافقی', NULL, 0, 'کمتر از 1 سال', '2025-08-19 12:06:16', '2025-08-19 12:08:42'),
