(4542, 5523, 'علی کاشفی', 'alikashefisaleh@gmail.com', '09304200404', '8', 'تهران', '117', 'تهران', '', NULL, 'مجرد', '1379', 'معافیت', '«حسابدار جوان و پرانرژی با تسلط بر اصول و استانداردهای حسابداری و تجربه در ثبت و کنترل اسناد مالی، تهیه گزارش‌های مالی و امور خزانه‌داری. آشنا به سامانه مودیان (کارپوشه)، سامانه جامع تجارت (تجارت داخلی)، تهیه و ارسال اظهارنامه ارزش افزوده، معاملات فصلی و اظهارنامه عملکرد. مسلط به نرم‌افزارهای حسابداری و اکسل، دقیق، مسئولیت‌پذیر و علاقه‌مند به یادگیری و رشد حرفه‌ای. توانمند در همکاری تیمی و انجام پروژه‌های مالی.»', 1, NULL, 'حسابدار', 'توافقی', 1, 1, 'بین 8 تا 10 سال', '2025-09-10 12:32:24', '2025-10-31 15:29:45'),
