(4629, 5645, 'سارا سلیمانی', 'sarasoleimani.sa@gmail.com', '09102524754', '8', 'تهران', '117', 'تهران', 'رسالت - منطقه 4', NULL, 'متاهل', '1377', NULL, 'دارای ۴ سال سابقه حسابداری و علاقه به افزایش تجربه و توانایی یادگیری \nمسلط به امور خزانه و تهیه و ارسال لیست بیمه و مالیات حقوق \nمسلط به معاملات فصلی ۱۶۹\nآشنا به سامانه مودیان و اظهارنامه \nمسلط ثبت اسناد روزانه \nفاکتور خرید و فروش \nبایگانی\nمسلط به تنخواه و تنخواه گردانی \nمسلط تهیه صورت مغایرت بانکی کلیه حساب های شرکت\nآشنا به تهیه گزارشات در زمان حسابرسی و رسیدگی مالیاتی \nتهیه گزارشات مدیریت \nتوانایی کار به صورت تیمی\nتجربه کاری در نرم افزار حسابداری سپیدار و همکاران سیستم', 1, NULL, 'حسابدار', 'توافقی', NULL, 0, 'کمتر از 5 سال', '2025-09-18 16:36:55', '2025-09-20 15:21:30'),
(4630, 5646, 'زهرا نجفی', NULL, '09198539485', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-18 23:15:07', '2025-09-18 23:15:07'),
(4631, 5647, 'فاطمه محروقی', 'Fateme.mahrooghi@gmail.com', '09199902980', '8', 'تهران', '117', 'تهران', 'افسریه - منطقه 15', NULL, 'مجرد', '1375', NULL, 'من یک حسابدار با تجربه در صنایع ساخت و ساز و بخش بازرگانی ، من همواره به دنبال بهبود فرآیندها و افزایش کارایی مالی هستم. با دارا بودن مدرک کارشناسی در مدیریت ،توانسته‌ام مهارت‌های تحلیلی و مدیریتی خود را تقویت کنم و در محیط‌های پویا و چالش‌برانگیز به خوبی عمل کنم. علاقه‌مند به ارائه راه‌حل‌های نوآورانه و کارآمد برای مسائل مالی و حسابداری هستم و همیشه آماده‌ام تا با تیم‌های پویا و خلاق همکاری کنم. باروحیه یادگیری و انگیزه بالا،به دنبال فرصت‌هایی هستم که بتوانم به رشد و موفقیت سازمان کمک کنم', 0, NULL, 'حسابدار', 'توافقی', NULL, 0, 'بین 5 تا 7 سال', '2025-09-19 11:38:54', '2025-09-19 14:33:31'),
