(4712, 5745, 'زهرا راست بین', 'zahra77rb@gmail.com', '09381232486', '8', 'تهران', '137', 'ملارد', '', NULL, 'مجرد', '1377', NULL, 'دانشجوی کارشناسی ارشد حسابداری.\n۴سال سابقه کار حسابداری و مالی.\nدقیق و موشکاف، در ثبت و تحلیل داده‌های مالی، با تعهد کامل به اصول اخلاقی.\nتوانایی صدور انواع اسنادحسابداری، ارسال انواع اظهارنامه های مالیاتی، مسلط به نرم‌افزارهای پیشرفته حسابداری.\nتوانایی برقراری ارتباط موثر و کار تیمی سازنده.\nتوانایی یادگیری سریع و سازگار، آماده برای انطباق با استانداردهای جدید و تکنولوژی‌های روز.\nمسئولیت‌پذیر، متعهد به اجرای بی‌نقص وظایف محوله.', 0, NULL, 'حسابدار', 'توافقی', NULL, 1, 'کمتر از 5 سال', '2025-09-25 17:46:05', '2025-09-25 18:00:48'),
