(5152, 6256, 'مهزاد معدلت پرور', 'madelatparvarmahzad@gmail.com', '09124290579', '8', 'تهران', '117', 'تهران', 'دماوند - منطقه 13', NULL, 'متاهل', '1368', NULL, 'سیزده سال سابقه کاری در شرکت های متخصص در زمینه حسابداری و مشاوره مالی و مالیاتی، حسابداری فروش و انبار،فروش و بازاریابی و راه اندازی سیستم حسابداری و آشنایی با کلیه نرم افزارهای مالی(بیمه، مالیات، ارزش افزوده، صورت فصلی،سامانه مودیان، دفاتر الکترونیکی، پرونده های مالیاتی)\n\nدر اجرای نرم افزار هلو، سپیدار،شایگان، همکاران سیستم، قیاس، رافع، دفترحساب، راهکاران، آمیسا، رویان نوین به طور کامل تجربه دارم و به کار با نرم افزار اکسل و ورد تسلط کامل دارم', 0, NULL, 'سرپرست حسابداری', '50 تا 60 میلیون تومان', 11, 0, 'بین 10 تا 15 سال', '2025-10-19 18:35:53', '2025-10-19 19:01:10'),
