(5164, 6268, 'محمد قاسمی', 'mgh9904@gmail.com', '09158612557', '31', 'یزد', '431', 'طبس', '', NULL, 'مجرد', '1375', 'اتمام سربازی', 'کارشناس حسابداری \nنرم افزار های حسابداری که کار کردم (محک و راهکاران)\nراهکاران (ماژول تدارکات و لجستیک و مالی) \nمسلط به اکسل \nبهای تمام شده و صورت های مالی و بودجه هم کار کردم\nدر حال حاضر در رابطه با هوش مصنوعی و حسابداری و کمک هوش مصنوعی به حسابداری در حال تحقیق می باشم', 1, NULL, 'حسابدار صنعتی', '50 تا 60 میلیون تومان', 11, 0, 'کمتر از 5 سال', '2025-10-20 11:33:41', '2025-10-20 11:48:20'),
(5165, 6269, 'فائزه حاجی غلام', 'f6023286@gmail.com', '09392603418', '5', 'البرز', '283', 'کرج', 'اتحاد', NULL, 'مجرد', '1374', NULL, 'با عرض سلام \nمن ۴ سال سابقه کاره حسابداری دارم \nو تسلط به نرم افزار سپیدار \nثبت سند در نرم افزار مغایرت گیری بانکی \nلیست بیمه و مالیات حقوق \nسامانه مودیان ارزش افزوده \nمغایرت گیری طرف حساب ها \nو توانستم در جلسه های رسیدگی مالیاتی شرکت کنم و مالیات آن شرکت را با توجه به قوانین و مقررات کاهش بدهم\nو بیشتر تمایل به انجام کاره پروژه ای حسابداری دارم و نمایندگی فروش نرم افزار ابری قیاس دارم و می توانم کار شرکت ها را به صورت پروژه ای با نرم افزار ابری انجام بدهم', 0, NULL, 'حسابدار', 'توافقی', 1, 0, 'بین 3 تا 4 سال', '2025-10-20 11:56:01', '2025-10-21 17:28:54'),
