(5200, 6309, 'اکبر خدایی', NULL, '09192272528', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'سابقه ۲۰ سال کار با نرم افزار هلو و تولیدی و نرم افزار محک  دارم سنم ۵۲ ساله\nکنترل هزینه\nمغایرت گیری حسابها وبانک ها\nقیمت تمام شده کالا\nکنترل بحران مالی \nکمک در صادرات کالا\nگزارش مالی متوالی و کنترل سود و ضرر و زیان\nآموزش ورود به نرم افزار به پرسنل شرکت\nآماده یادگیری در سطح بالا در امور مالی و کارهای محوله در هر مورد جهت کمک به شرکت وکارفرما \nشعار من حسابدار باید هزینه خودشو تو شرکت در روند کاریش در بیاره بس من باید به شرکت یا کارفرما سود برسونم که حقوق بگیرم', NULL, NULL, 'حسابدار', 'توافقی', 1, 0, 'بیشتر از 20 سال', '2025-10-21 15:46:32', '2025-10-21 16:13:40'),
