(5236, 6352, 'محمدرضا مرادی', NULL, '09372675566', '8', 'تهران', '136', 'قدس', '', NULL, 'مجرد', '1374', 'اتمام سربازی', 'دارای ۲ سال تجربه در حسابداری حقوق و دستمزد، تنخواه و انبار با تسلط بر نرم‌افزار سپیدار و Excel. آشنا با قوانین بیمه و مالیات. دارای روحیه مسئولیت‌پذیر و دقت بالا', 1, NULL, 'حسابدار', '30 تا 35 میلیون تومان', 7, 0, 'بین 1 تا 2 سال', '2025-10-24 09:18:35', '2025-10-24 09:35:37'),
(5237, 6353, 'مریم بامروت', NULL, '09906238556', '11', 'خراسان رضوی', '170', 'طرقبه', '', NULL, 'مجرد', '1362', NULL, 'من فردی دقیق، منظم و مسئولیت‌پذیر هستم و در انجام کارهای حسابداری دقت بالایی دارم. با نرم‌افزارهای حسابداری مانندانعکاس و اکسل آشنا هستم و می‌توانم گزارش‌های مالی، ثبت اسناد حسابداری، و مغایرت‌گیری بانکی را به‌طور دقیق انجام دهم. همچنین در کنترل هزینه‌ها، بررسی فاکتورها، و تهیه صورت‌حساب‌ها تجربه دارم. توانایی کار تیمی و مدیریت زمان از دیگر نقاط قوت من است.', 0, NULL, 'حسابدار', '25 تا 30 میلیون تومان', 6, 1, 'بین 10 تا 15 سال', '2025-10-24 09:56:06', '2025-10-24 10:15:51'),
(5238, 6354, 'هادی زارع', 'Zarehaby85@gmail.com', '09944293008', '31', 'یزد', '426', 'یزد', '', NULL, 'مجرد', '1385', 'معافیت', 'سابقه ۲ ماه حسابداری و فروشندگی مغازه تاسیساتی \nو کار با نرم افزار فرامحاسب و پیشرو \nحسابدار کارگاه گرانول و کار با نرم افزار وین تب', 1, NULL, 'کمک حسابدار', 'توافقی', 1, 0, 'کمتر از 1 سال', '2025-10-24 18:04:38', '2025-10-24 18:10:23'),
(5239, 6355, 'مرضیه منصوریان', 'marziyehmansourian85@gmail.com', '09125305546', '8', 'تهران', '117', 'تهران', 'بلوار فردوس - منطقه 5', NULL, 'مجرد', '1364', NULL, 'کارشناس حسابداری با بیش از 12سال تجربه در حوزه\nحسابداری و مالیات، آماده به اشرتاک گذاری خدمات حرفه ای\nخود در یک محیط پویا و چالش برانگیز می باشم. تخصص من\nشامل تعامل با مجریان مالیاتی و ارائه مشاوره مالی برای بهبود\nعملکرد سازمان است. دارای مهارت های فنی قوی، دقت باال و\nتوانایی همکاری در تیم هستم. نگرش منحرص به فرد و توانایی\nحل مسائل پیچیده، من را از دیگران متامیز می کند.', 0, NULL, 'رییس حسابداری', '45 تا 50 میلیون تومان', 10, 0, 'بین 10 تا 15 سال', '2025-10-24 18:15:01', '2025-10-24 18:27:04'),
(5240, 6356, 'خدیجه بهاروندی', 'baharalikhani672@gmail.com', '09023900579', '8', 'تهران', '117', 'تهران', 'استادمعین - منطقه 9', NULL, 'مجرد', '1363', NULL, 'حسابدار با5 سال سابقه در بخش تولید فولادوتسلط کامل بر سیستم خزانه و حسابداری انبار ، بهای تمام شده و فروش  تسلط کامل به سامانه مودیان ، اجرای دفاتر به صورت الکترونیک ،جامع تجارت و سیستم حقوق و بیمه و مالیات و مهارت در نرم افزارهای همکاران سیستم و سپیدار و همچنین تهیه گزارش ارزش افزوده و معاملات فصلی', 0, NULL, 'حسابدار', '40 تا 45 میلیون تومان', 9, 1, 'بیشتر از 5 سال', '2025-10-24 19:03:09', '2025-10-24 19:12:34'),
