(5279, 6397, 'معصومه یزدانی', NULL, '09059832115', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'سلام دررابطه بااگهی  حسابدار اینجانب حدود ۱۵ سال سابقه حسابداری دارم خانم هستم و در قسمت دولتی و خصوصی کار حسابداری انجام داده ام  از جمله کارشناس درامد شهرداری و حسابداربیلبوردهای شهری و کار با کارشناس حسابرسی و حسابداری و شرکت فارغ التحصیلان که کار ساخت و ساز پروژهای عمرانی داشتند و همچنین اشنایی با چندین نرم افزار مالی که البته هر مجموعهای از نرم افزار خاصی استفاده میکنه و مهم دانش به کارگیری هست دیپلم و فوق دیپلم حسابداری دارم و بیمه هم لازم ندارم', NULL, NULL, 'حسابدار', '15 تا 20 میلیون تومان', 4, 0, 'بین 10 تا 15 سال', '2025-10-26 13:23:35', '2025-10-26 13:26:07'),
(5280, 6398, 'مرضیه براتیان', 'baratian64@gmail.com', '09150015209', '11', 'خراسان رضوی', '153', 'مشهد', 'احمد آباد', NULL, 'مجرد', '1364', NULL, 'اینجانب تجربه کافی در ثبت و صدور اسناد حسابداری و همچنین ارائه گزارشات سود و زیان و گزارشات مورد درخواست مدیران و تنظیم و ارسال صورت معاملات فصلی، ارسال اظهارنامه ارزش افزوده ،پلمپ دفاتر و تحریر دفاتر،محاسبه حقوق و دستمزد،تهیه و ارسال لیست بیمه و مالیات حقوق و تنظیم و ارسال اظهارنامه عملکرد را دارم،و همچنین تجربه شرکت در جلسات حل اختلاف مالیاتی را نیز دارا می باشم.همچنین عضو جامعه مشاوران رسمی مالیاتی ایران می باشم .\nمهارت کار با نرم افزار حسابداری اوراش،سپیدار،آوید سیستم شرق -کیمیاو محک', 0, NULL, 'رییس حسابداری', '25 تا 30 میلیون تومان', 6, 0, 'بین 10 تا 15 سال', '2025-10-26 13:35:55', '2025-10-26 14:15:24'),
