(5482, 6613, 'سمانه پاسیار', 'Samaneh.pasyar@gmail.com', '09171503370', '17', 'فارس', '238', 'آباده', '', NULL, 'مجرد', '1362', NULL, 'فوق دیپلم حسابداری مالی  دارم و تجربه کار در شرکت های تولیدی، کارمند مالی بخشداری و هم اکنون همکاری دارم باپروژه های پیمانکاری در زمینه استخراج معدن خاک نسوز و معدن سیلیس به عنوان حسابدار مالی و مالیاتی، از سال۹۴ وارد بازار کار شدم، و بیمه و حقوق و دستمزد و تسلط کامل دارم، دوره بیمه تامین اجتماعی و مشاور بیمه رو گذروندم آشنایی کامل به مباحث مالیاتی و مسلط،به نرم افزار اکسل  تمایل به کار های پروژه ای و دور کاری ، برای درآمد بیشتر تمایل دارم علاوه بر کار فعلیم پروژه های دور کاری و بپذیرم', 0, NULL, 'حسابدار', '20 تا 25 میلیون تومان', 5, 1, 'بین 5 تا 7 سال', '2025-11-03 16:57:32', '2025-11-03 17:07:54'),
