(5513, 6644, 'محمود رضایی', NULL, '09124547753', '8', 'تهران', '117', 'تهران', '', NULL, 'متاهل', '1352', 'اتمام سربازی', 'اینجانب با ۳۰سابقه کاری تمام موارد مالی از ثبت اسناد مالی تهیه صورت مالی اظهارنامه اظهارنامه ارزش افزوده سامانه مودیان شرکت د  جلسات بیمه و مالیات درخدمت هستم', 1, NULL, 'مدیر مالی', '45 تا 50 میلیون تومان', 10, 1, 'بیشتر از 20 سال', '2025-11-05 21:19:27', '2025-12-12 14:09:01'),
