(5702, 6862, 'مریم میرحسینی', NULL, '09921325596', '31', 'یزد', '426', 'یزد', '', NULL, 'مجرد', '1383', NULL, 'من حسابداری را از هنرستان فنی حرفه ای  شروع کرده و دیپلم گرفتم و بعد از اون کاردانی را در دانشگاه دولتي فنی و حرفه‌ای گرفتم و الان ترم ۳ کارشناسی در همون دانشگاه هستم \n۱ ما کارآموزی ثبت احوال رفتم و ۲ ما یک شرکت پخش مواد غذایی و ۶ ما در یک آموزشگاه حسابداری \nنرم افزار سه نیک و سپیدار را دوره دیدم و در کارآموزی نرم افزار محک را آشنا شدم در دانشگاه نرم افزار نوسا و پیشرو و اکسل و ورد را آموزش دیدم', 0, NULL, 'حسابدار', 'توافقی', 1, 0, 'بدون سابقه کار', '2025-11-16 18:22:27', '2025-11-16 18:27:58'),
