(5818, 6986, 'فاطمه منفرد', NULL, '09125707352', '19', 'قم', '274', 'قم', '', NULL, 'مجرد', '1373', NULL, 'بنده معتقدم که حسابدار قلب یک مجموعس بنابراین کار باید به صورت دقیق و منظم و محرمانه انجام بشه. \nاینجانب دارای مدرک ارشد حسابرسی و سابقه ی کار در دفاتر مالیاتی ، کمک حسابرس و حسابداری بازرگانی را دارم. \nدر حال یادگیری مهارت های اکسل، زبان انگلیسی و حسابداری مقدماتی و تکمیلی ویژه بازار کار هستم. \nهمچنین تجربه ی کاری با نرم افزار های هلو و آسان و سپیدار را دارم.', 0, NULL, 'حسابدار', '15 تا 20 میلیون تومان', 4, 0, 'بین 3 تا 4 سال', '2025-11-19 08:23:35', '2025-11-19 08:39:12'),
