(5950, 7122, 'مریم خداشاهی', 'maryamkhodashahi051@gmail.com', '09028797098', '11', 'خراسان رضوی', '153', 'مشهد', 'احمد آباد', NULL, 'مجرد', '1372', NULL, 'خانم ۳۱ ساله مجرد\nمسئولیت پذیر، باهوش و با پشتکار، توانمند و علاقه مند به یادگیری و پیشرفت\nدارای روابط عمومی بالا \nکارشناسی علوم مهندسی', 0, NULL, 'حسابدار', '20 تا 25 میلیون تومان', 5, 0, 'بین 3 تا 4 سال', '2025-11-20 23:47:35', '2025-11-23 22:27:35'),
