(5953, 7125, 'سامان فاتحی', NULL, '09188775815', '30', 'همدان', '418', 'همدان', '', NULL, 'متاهل', '1361', 'اتمام سربازی', 'اینجانب سامان فاتحی بعنوان معاون مدیر مالی بمدت ۲۲سال سابقه خدمت در شرکت ملی پخش فرآورده های نفتی منطقه کردستان(سنندج) هستم ، همچنین دانشجوی دکتری حسابداری هستم و در زمینه های مالی ، حسابرسی و مالیاتی تجربه ، علم وعلاقه مند به همکاری با شرکتها و سازمانها هستم', 1, NULL, 'مشاور مالی', 'توافقی', 1, 1, 'بیشتر از 20 سال', '2025-11-21 06:29:21', '2025-11-23 07:50:19'),
(5954, 7126, 'الهه حسنوند', 'elahehhh8282@gmail.com', '09021824095', '8', 'تهران', '117', 'تهران', '', NULL, 'مجرد', '1382', NULL, 'فردی با انگیزه بالا و علاقه‌مند به کار اجرایی حسابداری، همراه با سابقه یک ساله در تیم‌های حسابرسی.\nبه صورت عملی با بخش‌های مختلف اسناد حسابداری و الزامات قانونی آشنا هستم و توانایی انجام سریع و دقیق وظایف روزمره حسابداری را دارم.\nبه دنبال فرصتی هستم که در کنار حقوق پایه، مسیر مشخصی برای آموزش و کسب تجربه وجود داشته باشد تا بتوانم در مدت زمان کوتاه، با ارتقاء دانش تئوری خود در استانداردها، نقشی کلیدی‌تر در واحد مالی ایفا کنم.', 0, NULL, 'کمک حسابدار', 'توافقی', 1, 0, 'بین 1 تا 2 سال', '2025-11-21 08:27:41', '2025-11-21 08:47:29'),
(5955, 7127, 'زهرا اصغری', 'asghari.zahra2000@gmail.com', '09396099630', '27', 'مازندران', '376', 'ساری', '', NULL, 'متاهل', '1379', NULL, 'حسابدار با تجربه و آشنا به اصول حسابداری، حقوق و دستمزد و نرم‌افزارهای مالی. مسلط به نرم‌افزارهای حسابداری از جمله سپیدار، هلو، اکسل پیشرفته و سایر ابزارهای مرتبط. توانمند در تهیه و تنظیم اسناد مالی، محاسبه دقیق حقوق و مزایا، ثبت و بایگانی اسناد حسابداری و همکاری مؤثر در تیم‌های مالی. دارای دقت بالا، مسئولیت‌پذیری و علاقه‌مند به یادگیری و پیشرفت در حوزه مالی و حسابداری', 0, NULL, 'حسابدار', 'توافقی', 1, 1, 'کمتر از 1 سال', '2025-11-21 10:18:22', '2025-11-21 10:27:29'),
(5956, 7128, 'آرتین شیخ الاسلامی', NULL, '09123802072', '8', 'تهران', '117', 'تهران', 'تهرانسر مرکزی - منطقه 21', NULL, 'متاهل', '1376', 'معافیت', 'روابط عمومی بالا\nسرعت بالا\nتوجه به قوانین و آئین نامه ها و به روز کردن دانش شخصی\nنظم در کار\nمسئولیت پذیری', 1, NULL, 'سرپرست حسابداری', 'توافقی', 1, 0, 'بین 8 تا 10 سال', '2025-11-21 10:18:57', '2025-11-21 10:40:26'),
