(6000, 7178, 'مهدی قاسمی', 'M70ghasemi@gmail.com', '09197817636', '8', 'تهران', '117', 'تهران', 'شادمهر - منطقه 2', NULL, 'متاهل', '1370', 'اتمام سربازی', 'دارای مدرک کارشناسی مالی ، مسلط به حسابداری مالی ، فروش، انبار، حقوق و دستمزد ، مسلط به بیمه و مالیات های عملکرد ارزش افزوده \n\nسابقه کار در شرکت های تولیدی و بازرگانی \nسابقه کار پاره وقت در زمینه رستوران و کافه و بازار مولوی\n\nسرگرمی های بنده دیدن فوتبال ، ورزش کردن در زمینه فوتبال و شنا', 1, NULL, 'رییس حسابداری', '35 تا 40 میلیون تومان', 8, 1, 'بین 10 تا 15 سال', '2025-11-23 11:17:38', '2025-11-23 11:22:31'),
(6001, 7179, 'عطیه سخی', NULL, '09196299127', '8', 'تهران', '117', 'تهران', 'گلستان غربی - منطقه 22', NULL, 'مجرد', '1370', NULL, 'ثبت فاکتورهای فروش و خرید و انبارگردانی \nکار با اکسل\nتهیه گزارش های مدیریت و کمک به مدیر مالی در تهیه برخی گزارش های مدیریتی\nسامانه مودیان\nگزارش نقدینگی\nثبت تنخواه \nمحاسبه حقوق و ارسال لیست بیمه\nمراجعه به امور مالیاتی\nهمکاری با مدیر مالی برای ارسال اظهارنامه مالیاتی\nمغایرتگیری \nدریافت پرداخت\nمعاملات فصلی و ارزش افزوده \nبرنامه: هلو-راهکاران-سپیدار-پیوست-تدبیر -ICDL\nعکاسی ؛ مطالعه ؛ آشپزی ؛ پیاده روی ؛ دوچرخه سواری و دویدن؛ ورزش و ....', 0, NULL, 'حسابدار', '30 تا 35 میلیون تومان', 7, 0, 'بین 8 تا 10 سال', '2025-11-23 12:33:22', '2025-11-23 13:44:48'),
