(6056, 7239, 'رامین تیمورزاده', 'ramin.teymoorzadeh@gmail.com', '09123704854', '8', 'تهران', '117', 'تهران', 'صادقیه شمالی شهرک هما - منطقه 2', NULL, 'متاهل', '1340', 'اتمام سربازی', 'لیسانس حسابداری سال ۶۸ دانشگاه آزاد مرکز و فوق لیسانس مدیریت بازرگانی از سازمان مدیریت صنعتی ، گواهینامه رسمی کامپیوتر İCDL از موسسه ایز ایران و دوره کامپیوتر از سازمان فنی حرفه آیی ، \nسابقه کار : \nمدیر مالی اداری طرحهای عمرانی صنایع دفاع \nمدیر مالی شرکت رنگ کرومات \nرئیس حسابداری خدماتی کیش سازمان عمران کیش\nرئیس حسابداری شرکت عمران ارگ وابسته به کرمان خودرو و منطقه ویژه اقتصادی \nسرپرست مالی اداری شرکت تاریر', 1, NULL, 'رییس حسابداری', 'توافقی', 1, 1, 'بیشتر از 20 سال', '2025-11-26 18:46:19', '2025-12-19 01:15:24'),
