(6061, 7245, 'مهیار عباس آبادی', NULL, '09934465676', '5', 'البرز', '283', 'کرج', 'شاهین ویلا', NULL, 'متاهل', '1369', 'معافیت', 'مشاور رسمی مالیاتی\nمدیریت مالی و مالیاتی شرکتها\nوکالت تخصصی پرونده های مالیاتی\nسال‌ها فعالیت در حوزه‌های مختلف تولیدی، خدماتی و بازرگانی به من آموخته که هر کسب‌وکار الگوی مالیاتی خاص خودش را دارد. بر همین اساس، تخصصم حول سه محور شکل گرفته: مدیریت ریسک‌های مالیاتی، ارائه راهکارهای قانونی برای کاهش هزینه‌ها، و همراهی حرفه‌ای در رسیدگی و دادرسی‌ها. در پروژه‌ها، معمولاً با تحلیل داده‌های مالی، بررسی قراردادها، و تطبیق فرآیندها با قوانین، مسیر کم‌ریسک و قابل اتکای شرکت را مشخص می‌کنم.', 1, NULL, 'مشاور مالی', '35 تا 40 میلیون تومان', 8, 1, 'بین 10 تا 15 سال', '2025-11-27 12:14:14', '2025-11-27 12:25:39'),
