(6241, 7434, 'صبا حسین زاده', 'Sabahoseinzade2@jmail.com', '09194351124', '8', 'تهران', '135', 'رباط کریم', '', NULL, 'مجرد', '1380', NULL, '_ تسلط کامل به نرم افزار های حسابداری\n_ مدیریت و ثبت دقیق  تراکنش‌های مالی در نرم افزار حسابداری سپیدار \n_  تهیه و تجزیه و تحلیل گزارش‌های مالی ماهانه و سالانه برای بهبود تصمیم‌گیری‌های مدیریتی\n_  بررسی و تطبیق اسناد مالی با صورت های حساب بانکی و موجودی ها \n_ تهیه لیست بیمه و ارسال در سایت تامین اجتماعی \n_ تهیه لیست حقوق و دستمز کارکنان و ارسال مالیات حقوق در سامانه مودیان \n_ دارای مدارک حسابداری و icdl از آموزشگاه فنی و حرفه ای', 0, NULL, 'حسابدار', '25 تا 30 میلیون تومان', 6, 0, 'بین 3 تا 4 سال', '2025-12-05 12:48:56', '2025-12-05 13:28:21'),
(6242, 7435, 'اکبر قلی زاده', NULL, '09124369215', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'باسلام اینجانب باسابقه ۲۸ سال سابقه حسابداری و مدیریت مالی.ومسلط به قوانین و استاندارهای حسابداری .', NULL, NULL, 'مدیر مالی', '50 تا 60 میلیون تومان', 11, 1, 'بیشتر از 20 سال', '2025-12-05 13:35:46', '2025-12-05 13:39:24'),
(6243, 7436, 'محمود اسلام دوست', 'Eslamdoost.98@gmail.com', '09017820814', '13', 'خوزستان', '179', 'اهواز', '', NULL, 'متاهل', '1353', 'اتمام سربازی', 'کاردانی و کارشناسی حسابداری\nآشنایی با نرم افزار هلو و سایر نرم افزارهای مالی\nآشنایی با تحریر دفاتر\nآشنایی با انواع اظهارنامه های مالیاتی\nاعم از عملکرد و ارزش افزوده و فصلی و...... \nتهیه ی لیست حقوق و دستمزد\nتهیه ی لیست مالیاتی \nتهیه.......', 1, NULL, 'حسابدار', '20 تا 25 میلیون تومان', 5, 1, 'بین 15 تا 20 سال', '2025-12-05 13:43:57', '2025-12-05 13:50:46'),
