(6339, 7541, 'مریم یوسفی', 'maryamyousefi500@gmail.com', '09210740625', '17', 'فارس', '232', 'شیراز', '', NULL, 'مجرد', '1374', NULL, 'من یک خانم علاقمند به رشته حسابداری هستم و مدرک دانشگاهی من مهندسی گیاه پزشکی است ولی دوره های آموزشی حسابداری بازار کار را گذرانده ام و هدفم برای شروع در این حرفه کمک حسابدار است تا بتونم به صورت عملی هم تجربه کسب کنم و تو این زمینه رشد کنم.\nو  همچنین در زمینه کاری و زندگی شخصیم (نظم،دقت،صداقت،راز داری،تعهد )ارزش بسیار بالایی دارند.', 0, NULL, 'کمک حسابدار', 'توافقی', 1, 0, 'بدون سابقه کار', '2025-12-08 17:08:39', '2025-12-08 17:31:35'),
(6340, 7543, 'سیده مریم موسوی', 'sm.moosavi229@gmail.com', '09118256998', '25', 'گیلان', '341', 'رشت', '', NULL, 'متاهل', '1363', NULL, 'سیده مریم موسوی، کارشناس ارشد مالی و از دانشجویان استعدادهای درخشان، با سابقه یک‌ونیم سال همکاری در سازمان تأمین اجتماعی (واحدهای درآمد، سوابق، نام‌نویسی و امور اداری) دارای مهارت در امور سازمانی، مدیریت پرونده‌ها و ارتباط با ارباب‌رجوع است. به نرم‌افزارهای حسابداری سپیدار و هلو مسلط بوده و با وجود نداشتن سابقه مستقیم حسابداری، از پشتکار، یادگیری سریع، روحیه تیمی، تعهد کاری و توان حل مسئله برخوردار است و آماده فعالیت مؤثر در حوزه مالی و حسابداری می‌باشد.', 0, NULL, 'کمک حسابدار', 'قانون کار', 0, 0, 'بدون سابقه کار', '2025-12-08 17:17:36', '2025-12-08 17:24:50'),
(6341, 7544, 'سمیرا کرمی', NULL, '09196400337', '8', 'تهران', '117', 'تهران', 'جنت آباد - منطقه 5', NULL, 'متاهل', '1363', NULL, 'باتوجه به فعالیتهای انجام شده توانایی کنترل و نظارت براسناد و گزارش طبق درخواست مدیریت و مدیر مالی کنترل و ارسال  سامانه مودیان ،اظهار نامه ارزش افزوده لیست بیمه و مالیات حقوق مغایرت گیری', 0, NULL, 'سرپرست حسابداری', 'توافقی', 1, 0, 'بین 10 تا 15 سال', '2025-12-08 17:53:01', '2025-12-10 14:02:45'),
