(6348, 7551, 'سارا حسن پور', 'Sarahhassanpour1@gmail.com', '09353592946', '8', 'تهران', '117', 'تهران', '', NULL, 'متاهل', '1377', NULL, 'سلام\nمن یک حسابدار حرفه‌ای با چند سال تجربه در زمینه حسابداری مالی، مالیاتی و گزارش‌دهی هستم. تخصص من در تهیه دفاتر مالی، مدیریت مالی و تحلیل هزینه‌هاست و به قوانین مالیاتی و استانداردهای حسابداری کاملاً مشرف هستم.  \nمن متعهد به دقت، رعایت زمان‌بندی و ارائه گزارش‌های جامع هستم تا کسب‌وکار شما بتواند تصمیمات مالی بهتری بگیرد.  \nاگر به دنبال کسی هستید که امور مالی شما را به بهترین نحو مدیریت کند، من آماده همکاری با شما هستم.', 0, NULL, 'حسابدار', 'توافقی', 1, 1, 'بیشتر از 5 سال', '2025-12-08 23:27:01', '2025-12-08 23:30:08'),
(6349, 7552, 'سجاد نیک پی', 'sajad.nikpey@yahoo.com', '09160612079', '13', 'خوزستان', '179', 'اهواز', '', NULL, 'متاهل', '1366', 'اتمام سربازی', 'با سلام\nفوق لیسانس حسابداری هستم دارای 15 سال سابقه کار حسابداری در دانشگاه علوم پزشکی جندی شاپور اهواز. در کنار کار حسابداری دانشگاه،  پروژه حسابداری ساختمانی انجام دادم‌‌. نسبت به نرم افزار های حسابداری و اکسل اشراف دارم. اهل ورزش هستم و در ساعات آزاد ورزش میکنم.', 1, NULL, 'حسابدار', 'توافقی', 1, 1, 'بین 10 تا 15 سال', '2025-12-09 00:12:21', '2025-12-09 00:17:13'),
