(6440, 7645, 'مینا امیدلو', 'minaomidi1383@gmail.com', '09039614494', '8', 'تهران', '136', 'قدس', '', NULL, 'مجرد', '1383', NULL, 'حسابدار با ۳ سال سابقه کار در حوزه مالی و اداری هستم که در ثبت و کنترل اسناد حسابداری، تهیه گزارش‌های مالی، مغایرت‌گیری بانکی و کار با نرم‌افزارهای حسابداری تجربه عملی دارم. دارای دقت بالا، توانایی تحلیل داده‌های مالی و مدیریت زمان مؤثر هستم. به نظم، مسئولیت‌پذیری و به‌روزرسانی مداوم دانش مالی خود اهمیت می‌دهم و تلاش می‌کنم در هر محیط کاری نقش مؤثری در بهبود فرآیندهای حسابداری و شفافیت مالی داشته باشم.', 0, NULL, 'حسابدار', '25 تا 30 میلیون تومان', 6, 1, 'بین 3 تا 4 سال', '2025-12-10 07:59:07', '2025-12-10 08:14:45'),
