(7125, 8351, 'محمدمهدی عباسیان', NULL, '09019844482', '8', 'تهران', '117', 'تهران', 'افسریه جنوبی - منطقه 15', NULL, 'مجرد', '1382', 'معافیت', 'اینجانب محمدمهدی عباسیان از سال ۱۴۰۱ مشغول به کار در زمینه مالی و مالیاتی میباشم و به تمامی مباحث مالی اشراف نسبتا کاملی دارم و با اکثر نرم افزارهای مالی اشنایی دارم همچنین به مباحث ذیل تسلط دارم: نظارت و مدیریت عملیات مالی و اداری شرکت ، تهیه و ارایه گزارش ‌های مالی دقیق و به موقع، تحلیل داده ‌های مالی و ارایه پیشنهادات استراتژیک، نظارت بر برنامه‌ریزی مالی تضمین، ارایه مشاوره و پشتیبانی به تیم مدیریت در تصمیم‌گیری ‌های مالی و برقراری ارتباط و همکاری موثر با نهادهای مالی.', 1, NULL, 'حسابدار', 'توافقی', 1, 0, 'بین 3 تا 4 سال', '2025-12-18 20:36:34', '2025-12-18 21:10:51'),
