(7387, 8624, 'فاطمه اذرکیش', 'Fatemeh.azarkish13@gmail.com', '09336343540', '8', 'تهران', '117', 'تهران', 'تهرانپارس غربی - منطقه 4', NULL, 'مجرد', '1384', NULL, 'دانشجوی کارشناسی حسابداری | ترم سوم\n\nعلاقه‌مند به یادگیری و پیشرفت در حوزه مالی و حسابداری\n\nمسلط به نرم‌افزارهای Word و Excel و آشنا با مفاهیم پایه حسابداری\n\n با تجربه کارآموزی در امور مالی و تسلط به نرم‌افزار سپیدار. آشنا با فرآیندهای دریافت و پرداخت، خرید و فروش، انبار، حقوق و دستمزد و هزینه‌ها... دارای مهارت در بایگانی اسناد، مغایرت‌گیری بانکی و ثبت تنخواه،آشنا با بیمه و مالیات و قانون و گزارش‌گیری مالی. فردی اجتماعی، منظم، با انگیزه یادگیری بالا و علاقه‌مند به پیشرفت در حوزه حسابداری و مالی.', 0, NULL, 'کمک حسابدار', 'توافقی', 1, 0, 'کمتر از 1 سال', '2025-12-25 20:24:05', '2025-12-26 23:32:52'),
