(7397, 8634, 'لعیا اولادشنبه', NULL, '09034019108', '17', 'فارس', '232', 'شیراز', '', NULL, 'مجرد', '1383', NULL, 'تحصیلات :دانشجوی ترم شش حسابداری \nواحد های پاس شده:حسابداری صنعتی ،حسابرسی، مدیریت مالی با نمره خوب \n*دوره ها و مهارت ها*:\n•گذروندن دوره کاربردی بازار کار حسابداری با نرم افزار سپیدار و اکسل در اموزشگاه معتبر\n•تسلط به ماژول های مالی ، خرید و فروش، انبار، صدور فاکتور و سندزنی \n•تجربه عملی در ورود اطلاعات و صدور اسناد \n\nسوابق کاری :\nدر حال حاضر تجربه کار رسمی ندارم اما مشتاقم که در محیط شرکتی شروع کنم و سریع یاد بگیرم.', 0, NULL, 'کمک حسابدار', '9 تا 12 میلیون تومان', 2, 0, 'بدون سابقه کار', '2025-12-25 23:50:30', '2025-12-25 23:54:25'),
(7398, 8635, 'پیناربخشی', 'Pinarbakhshi1381@gmail.com', '09037482665', '1', 'آذربایجان شرقی', '1', 'تبریز', '', NULL, 'مجرد', '1381', NULL, 'فوق دیپلم حسابداری دانشگاه سراسری \nمدرک پایان دوره آموزشگاه حسابداری آپاداس تبریز \nو مدرک حسابداری فنی و حرفه ای \n ۴ سال سابقه مدیرفروش در شرکت بازاریابان ایرانیان زمین', 0, NULL, 'حسابدار', 'توافقی', 1, 0, 'کمتر از 1 سال', '2025-12-26 00:02:08', '2025-12-26 00:11:06'),
(7399, 8636, 'لیلی رحیم پور ازغدی', NULL, '09155070048', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'لیسانس حسابداری هستم ۸ سال سابقه کار در شرکت اقماری برق خراسان در حوزه رییس حقوق دستمزد و کار با نرمافزلرهای  مالی و پس از بازخرید از شرکت برق به دلیل بدنیا آمدن  فرزندم و ساعت کار طولانی در شرکت خصوصی کیمیا توسعه ساختمانی بعنوان مدیر مالی بصورت پاره وقت و ۵ ساعت در روز به مدت پنج سال ادامه کار مالی در حوزه مالی ادامه دادم  و اللن نیز در خواست کار پاره وقت یا پنج روز در هفته به مدت ۵ ساعت نیز هستم  ممنون', NULL, NULL, 'رییس حسابداری', '15 تا 20 میلیون تومان', 4, 0, 'بین 10 تا 15 سال', '2025-12-26 00:14:13', '2025-12-26 00:21:10'),
